#include <stdio.h>

int main() {
    // Open document.txt in "r" (Read) mode
    FILE *filePtr = fopen("document.txt", "r");

    // Always check for NULL!
    if (filePtr == NULL) {
        printf("Error: File could not be found!\n");
        return 1; // Exit with error
    }

    printf("File opened successfully!\n");

    // Don't forget to close it when done!
    fclose(filePtr);
    return 0;
}

#include <stdio.h>

int main() {
    FILE *file = fopen("greeting.txt", "r");
    if (file != NULL) {
        char buffer[100]; // Create an empty array to hold the text

        // Read up to 100 characters from the file into the buffer
        while (fgets(buffer, 100, file) != NULL) {
            printf("Read line: %s", buffer);
        }

        fclose(file); // NEVER FORGET TO CLOSE!
    }
    return 0;
}
